import React, { useEffect, useRef, useContext, useMemo } from 'react'
import PropTypes from 'prop-types'
import { css } from '@linaria/core'
import { boolAttr, useEvent, useTimer } from '@fs/zion-frontend-friends'
import { ContentCheck, NoticeImportant, NoticeWarning, MenuClose } from '@fs/zion-icon'
import { useTranslation } from 'react-i18next'
import { useDrag } from 'react-use-gesture'
import { useSpring, animated } from '@react-spring/web'
import { Theme, colors } from '../theme'
import { Paragraph } from '../typography'
import { Button, IconButton } from '../buttons'
import Row from '../row'
import { GridStart } from '../grid'
import { ResponsiveProvider, usePageWidth } from '../responsive'
import Elevation from '../elevation'
import Portal from '../portal'
import useCancelClickAway from '../use-click-away/useCancelClickAway'
import useEscHandler from '../use-esc-handler'
import { ProgressOverlayContext } from '../progress-overlay/ProgressOverlayContext'
import { textDirection } from '../rtl-support'

const ariaAlertMessageTypes = {
  normal: ['status.overlay.message', 'Message'],
  error: ['status.overlay.message.error', 'Error Message'],
  warning: ['status.overlay.message.warning', 'Warning Message'],
  success: ['status.overlay.message.success', 'Success Message'],
}

const overlayCss = css`
  z-index: 2; /* Create a stacking context, so all things inside this overlay will be contained (and on top of the main ui) */
  position: fixed;
  inset-inline-start: 12px;
  inset-inline-end: 12px;
  bottom: 12px;
  touch-action: none;
  user-select: none;

  &:focus-visible {
    outline: 2px solid ${colors.gray70};
    outline-offset: 2px;
    border-radius: 4px;
  }

  &[is-large-screen] {
    width: 400px;
    inset-inline-start: auto;
    inset-inline-end: 24px;
    bottom: auto;
    top: calc(24px + var(--role-indicator-height, 0px));
  }
`

const statusOverlayCss = css`
  padding: 16px;
  border-radius: 4px;
  background: ${colors.gray02};
  position: relative;
`

function TypeIcon({ type }) {
  switch (type) {
    case 'error':
      return <NoticeImportant color={colors.danger60} />
    case 'warning':
      return <NoticeWarning color={colors.yellow70} />
    case 'success':
      return <ContentCheck color={colors.green70} />
    default:
      return null
  }
}

function calculateShouldDismiss({ dragDistance, direction, velocity, targetDistance, invertGesture }) {
  // we gucci if velocity and direction is going to put it past the targetDistance
  const trajectory = dragDistance + velocity * 15 * direction * (invertGesture ? -1 : 1)
  return invertGesture ? trajectory < -targetDistance : trajectory > targetDistance
}

const calculateDuration = (message, actionLabel) => {
  const num = message.length * 65 + 1500
  return actionLabel ? 20000 : Math.min(Math.max(num, 6000), 20000)
}

const getDefaults = (isRtl = false) => ({
  show: { x: 0, y: 0 },
  large: {
    axis: 'x',
    targetDistance: 56,
    hide: { x: isRtl ? -500 : 500, y: 0 },
  },
  small: {
    axis: 'y',
    targetDistance: 36,
    hide: { x: 0, y: 300 },
  },
})

/** Status Overlay is a secondary type message displayed for a short period of time to the user. */
function StatusOverlay({
  message,
  type = 'normal',
  Icon,
  actionLabel,
  actionCallback,

  /** [HIDDEN]: For internal Zion-UI use only */
  messageState,
  enter,
  leave,
  remove,
}) {
  const isRtl = textDirection() === 'rtl'
  const defaults = useMemo(() => getDefaults(isRtl), [isRtl])
  const onRest = useRef()
  const mode = usePageWidth()({ default: 'small', md: 'large' })
  const control = useRef(defaults[mode])
  const [t] = useTranslation()
  const ariaAlertMessage = ariaAlertMessageTypes[type] || ariaAlertMessageTypes.normal
  const { startTimer: countdown, pauseTimer, resetTimer } = useTimer()
  const { screenBottom } = useContext(ProgressOverlayContext)

  // Handler to pause timer on user interaction (WCAG compliant pause/resume pattern)
  const handleUserInteraction = useEvent(() => pauseTimer())

  // Handler to resume timer when user leaves the overlay
  const handleUserLeave = useEvent(() => {
    countdown(calculateDuration(message, actionLabel), leave)
  })

  const startTimer = useEvent(() => {
    countdown(calculateDuration(message, actionLabel), leave)
  })

  const [{ x, y }, api] = useSpring(() => ({
    from: defaults[mode].hide,
    to: defaults.show,
    onRest: () => {
      onRest.current?.()
    },
  }))

  const bind = useDrag(({ movement: [mx, my], velocity, direction: [dx, dy], down, tap }) => {
    // Handle tap events for timer pause/resume (mobile touch support)
    if (tap) {
      handleUserInteraction()
      return
    }

    const { axis, targetDistance } = control.current
    const dragDistance = axis === 'x' ? mx : my
    const direction = axis === 'x' ? dx : dy
    const invertGesture = axis === 'x' && isRtl

    if (down) {
      // Pause the timer when they start dragging
      pauseTimer()
      const shouldRubberBand = invertGesture ? dragDistance > 0 : dragDistance < 0
      api.start({ [axis]: dragDistance / (shouldRubberBand ? 8 : 1) - screenBottom })
    } else {
      // If a person dragged in a way that shows they want the overlay to go away, dismiss it
      const shouldDismiss = calculateShouldDismiss({ dragDistance, direction, velocity, targetDistance, invertGesture })
      if (shouldDismiss) {
        leave()
      } else {
        api.start(defaults.show)
        // Resume timer after drag gesture completes
        startTimer()
      }
    }
  })

  // Update animating position of overlay, depending on what state it's in
  useEffect(() => {
    const { hide } = control.current
    switch (messageState) {
      case 'hidden':
        startTimer()
        api.start(defaults.show)
        onRest.current = null
        enter()
        break

      case 'leaving':
        api.start(hide)
        onRest.current = remove
        resetTimer()
        break

      default:
      // do nothing
    }
  }, [messageState, remove, enter, startTimer, resetTimer, api, defaults])

  useEffect(() => {
    control.current = defaults[mode]
  }, [defaults, mode])

  useEffect(() => {
    /** On mobile, set the y axis value to 'bottom' so that StatusOverlay moves above ProgressOverlay.
     *  When ProgressOverlay is visible, it sets the 'bottom' property of StatusOverlay. */
    if (mode === 'small') {
      defaults.show.y = -screenBottom
      api.start(defaults.show)
    }
  }, [screenBottom, mode, api, defaults])

  // Provide close-on-escape functionality, because StatusOverlay is always swipe-dismissible
  useEscHandler({
    handler: leave,
    enabled: true,
  })

  return (
    <Portal>
      <animated.div
        data-testid="status-overlay"
        className={overlayCss}
        is-large-screen={boolAttr(mode === 'large')}
        style={{ x, y }}
        tabIndex={0}
        {...bind()}
        onMouseEnter={handleUserInteraction}
        onMouseMove={handleUserInteraction}
        onMouseLeave={handleUserLeave}
        onClick={handleUserInteraction}
        onFocus={handleUserInteraction}
        onBlur={handleUserLeave}
        onKeyDown={handleUserInteraction}
      >
        <Elevation z={6} as={Theme} theme="night" onMouseDown={useCancelClickAway()} className={statusOverlayCss}>
          <ResponsiveProvider>
            <GridStart>
              <Row role="alert" gutters="xxs" aria-label={t(...ariaAlertMessage)}>
                {((type !== 'normal' || Icon) &&
                  (Icon ? <Icon noShrinkX color={colors.gray70} /> : <TypeIcon noShrinkX type={type} />)) ||
                  null}
                <Paragraph growX size="sm">
                  {message}
                </Paragraph>
                <IconButton
                  alignY="top"
                  noShrinkX
                  color="gray"
                  type="button"
                  Icon={MenuClose}
                  onClick={leave}
                  aria-label={t('status.overlay.dismiss.action', 'Dismiss')}
                  title={t('status.overlay.dismiss.action', 'Dismiss')}
                  size="sm"
                />
              </Row>
              {actionLabel && (
                <Row alignX="end">
                  <Button
                    type="button"
                    dense
                    onClick={() => {
                      leave()
                      actionCallback()
                    }}
                  >
                    {actionLabel}
                  </Button>
                </Row>
              )}
            </GridStart>
          </ResponsiveProvider>
        </Elevation>
      </animated.div>
    </Portal>
  )
}

StatusOverlay.propTypes = {
  /** Text to show in the status overlay */
  message: PropTypes.string.isRequired,

  /** Type of message and icon to display (normal = no icon). */
  type: PropTypes.oneOf(['normal', 'error', 'warning', 'success']),

  /** The Icon component you may want to render. */
  Icon: PropTypes.elementType,

  /** If true, the overlay will close if another one is triggered to open. */
  transient: PropTypes.bool,

  /** The label for the action button (optional). */
  actionLabel: PropTypes.string,

  /** The callback for the action (required if actionLabel is used). */
  actionCallback: PropTypes.func,

  /** [HIDDEN]: current state of the overlay */
  // messageState: PropTypes.oneOf(['hidden', 'entering', 'leaving']),
  /** [HIDDEN]: callback to mark the overlay as entering */
  // enter: PropTypes.func,
  /** [HIDDEN]: callback to set show to false and transition out */
  // leave: PropTypes.func,
  /** [HIDDEN]: Callback to remove the overlay from the state array */
  // remove: PropTypes.func,
}

export default StatusOverlay
